SELECT SUM(tax_amount) AS total_tax_due
FROM tax_bills
WHERE tax_year = 2023;

SELECT SUM(tax_revenue) AS total_tax_revenue
FROM district_tax_revenue
WHERE tax_year = 2023;

SELECT SUM(revenue_amount) AS total_revenue
FROM revenue_reports
WHERE report_type = 'monthly' AND report_date LIKE '2023-01-%';

SELECT COUNT(*) AS unpaid_count
FROM tax_bills
WHERE tax_year = 2023 AND payment_status = 'unpaid';

SELECT district_name
FROM taxing_districts
ORDER BY district_name ASC;

SELECT tax_amount
FROM tax_bills
WHERE tax_year = 2023 AND payment_status = 'unpaid';

SELECT tax_revenue
FROM district_tax_revenue
WHERE district_id = 1 AND tax_year = 2023;

SELECT COUNT(*) AS total_delinquencies
FROM delinquencies
WHERE strftime('%Y', delinquency_date) = '2023';

SELECT SUM(revenue_amount) AS total_revenue
FROM revenue_reports
WHERE district_id = 1;

SELECT district_name, description, jurisdiction
FROM taxing_districts
ORDER BY district_name ASC;

SELECT revenue_amount
FROM revenue_reports
WHERE district_id = 0;
